function getPartyPage(party: string): (typeof partyPages)[keyof typeof partyPages] {
    assert(party in partyPages, `Party ${party} not found in partyPages data`)
    return partyPages[party as keyof typeof partyPages]
}

/** Party hue used for links and run cell backgrounds; mirrors `RepresentativeParty`. */
function partyHueColorString(colors: Colors, party: string | null | undefined): string | undefined {
    if (!party || party === 'Independent') {
        return undefined
    }
    if (!(party in partyPages)) {
        return undefined
    }
    const partyPage = partyPages[party as keyof typeof partyPages]
    // eslint-disable-next-line no-restricted-syntax -- not actual colors, just remapping
    const colorStr = partyPage.party_color === 'black' || partyPage.party_color === 'gray' ? 'grey' : partyPage.party_color
    return colors.hueColors[colorStr as keyof typeof colors.hueColors]
}

const runFillMix = 0.8
/** Stripe width per representative in proportional party hatching (see `displayRunFillStyle`). */
const hatchPixelsPerCount = 20

function mixedPartyFill(colors: Colors, hue: string): string {
    return mixWithBackground(hue, runFillMix, colors.cleanBackground)
}

/**
 * Solid tint for a single mappable party, or 45° diagonal stripes with widths proportional
 * to representative counts per party (e.g. 5 Dems / 4 Reps → 5k px blue then 4k red per repeat, k constant).
 */
function displayRunFillStyle(
    colors: Colors,
    representatives: CongressionalRepresentativeEntry['representative'][],
): Pick<CSSProperties, 'backgroundColor' | 'backgroundImage'> | undefined {
    const partyCounts = new Map<string, { count: number, hue: string }>()
    for (const rep of representatives) {
        const hue = partyHueColorString(colors, rep.party)
        if (!hue || !rep.party) {
            continue
        }
        const prev = partyCounts.get(rep.party)
        if (prev) {
            prev.count += 1
        }
        else {
            partyCounts.set(rep.party, { count: 1, hue })
        }
    }
    if (partyCounts.size === 0) {
        return undefined
    }
    const entries = [...partyCounts.entries()]
        .map(([party, { count, hue }]) => ({ party, count, hue }))
        .sort((a, b) => a.party.localeCompare(b.party))

    if (entries.length === 1) {
        return { backgroundColor: mixedPartyFill(colors, entries[0].hue) }
    }

    const stripeUnitPx = hatchPixelsPerCount
    const stops: string[] = []
    let posPx = 0
    for (const { count, hue } of entries) {
        const w = count * stripeUnitPx
        const c = mixedPartyFill(colors, hue)
        stops.push(`${c} ${posPx}px`, `${c} ${posPx + w}px`)
        posPx += w
    }
    return { backgroundImage: `repeating-linear-gradient(-45deg, ${stops.join(', ')})` }
}

function RepresentativeParty(props: { party?: string | null }): ReactNode {
    const colors = useColors()
    if (!props.party || props.party === 'Independent') {
        return null
    }
    const partyPage = getPartyPage(props.party)
    // eslint-disable-next-line no-restricted-syntax -- not actual colors, just remapping
    const colorStr = partyPage.party_color === 'black' || partyPage.party_color === 'gray' ? 'grey' : partyPage.party_color
    const color = colors.hueColors[colorStr]

    return (
        <a href={partyPage.wikipedia_page} style={{ textDecoration: 'none', color }} target="_blank" rel="noopener noreferrer">
            {` (${props.party.slice(0, 1)})`}
        </a>
    )
}

function Representative(props: { representative: CongressionalRepresentativeEntry['representative'] }): ReactNode {
    if (props.representative.name === 'Vacant') {
        return <span>(Vacant)</span>
    }
    return (
        <span>
            <a href={props.representative.wikipediaPage} style={{ textDecoration: 'none', color: 'inherit' }} target="_blank" rel="noopener noreferrer">
                {props.representative.name}
            </a>
            <RepresentativeParty party={props.representative.party ?? undefined} />
        </span>
    )
}

function districtArticleHref(nav: Navigator, longnames: string[]): NavLink {
    assert(longnames.length > 0, 'districtArticleHref requires at least one longname')
    if (longnames.length === 1) {
        return nav.link({
            kind: 'article',
            longname: longnames[0],
        }, { scroll: { kind: 'position', top: 0 } })
    }
    return nav.link({
        kind: 'comparison',
        longnames,
    }, { scroll: { kind: 'position', top: 0 } })
}

function borderStyles(props: {
    borderColor: string
    borderTop?: boolean
    borderRight?: boolean
    borderBottom?: boolean
    borderLeft?: boolean
}): CSSProperties {
    return {
        borderTop: props.borderTop ? `1px solid ${props.borderColor}` : undefined,
        borderRight: props.borderRight ? `1px solid ${props.borderColor}` : undefined,
        borderBottom: props.borderBottom ? `1px solid ${props.borderColor}` : undefined,
        borderLeft: props.borderLeft ? `1px solid ${props.borderColor}` : undefined,
    }
}

const padding = '0.2em 0.25em'

function baseTableCellStyle(props: {
    borderColor: string
    borderBottom?: boolean
    borderLeft?: boolean
    borderRight?: boolean
    textAlign?: 'left' | 'right' | 'center'
    display?: CSSProperties['display']
    justifyContent?: CSSProperties['justifyContent']
    alignItems?: CSSProperties['alignItems']
    backgroundColor?: string
}): CSSProperties {
    return {
        padding,
        display: props.display ?? 'flex',
        alignItems: props.alignItems ?? 'center',
        justifyContent: props.justifyContent ?? 'flex-end',
        textAlign: props.textAlign ?? 'right',
        backgroundColor: props.backgroundColor,
        ...borderStyles(props),
    }
}

function CongressionalTableTermLabels(props: {
    displayRows: CongressionalDisplayRow[]
    borderColor: string
}): ReactNode {
    const colors = useColors()
    return (
        <>
            {props.displayRows.map((row, displayIndex) => (
                <div
                    key={displayIndex}
                    data-display-index={displayIndex}
                    style={{
                        gridColumn: 1,
                        gridRow: displayIndex + 2,
                        ...baseTableCellStyle({
                            borderColor: props.borderColor,
                            borderBottom: displayIndex !== props.displayRows.length - 1,
                        }),
                        fontWeight: 500,
                        ...interSupercolumnBorder(colors, false),
                    }}
                >
                    {row.kind === 'term-label' ? formatTermLabel(row.termStart) : ''}
                </div>
            ))}
        </>
    )
}

function interSupercolumnBorder(colors: Colors, disable: boolean): CSSProperties {
    if (disable) {
        return {}
    }
    return { borderRight: `3px solid ${colors.textMain}` }
}

function CongressionalTableColumnHeaders(props: {
    supercolumns: RepresentativesForRegion[]
    borderColor: string
    panelBackground: string
}): ReactNode {
    const colors = useColors()
    return (
        <>
            {props.supercolumns.map((column, columnIndex) => (
                <div
                    key={columnIndex}
                    style={{
                        gridColumn: columnIndex + 2,
                        gridRow: 1,
                        ...baseTableCellStyle({
                            borderColor: props.borderColor,
                            // borderRight: true,
                            borderBottom: true,
                            textAlign: 'center',
                            justifyContent: 'center',
                            backgroundColor: props.panelBackground,
                        }),
                        fontWeight: 500,
                        ...interSupercolumnBorder(colors, columnIndex === props.supercolumns.length - 1),
                    }}
                >
                    {column.longname}
                </div>
            ))}
        </>
    )
}

function CongressionalTableSectionDistrictHeaders(props: {
    section: RepresentativesForRegionAndDistrictSet
    headerDisplayIndex: number
    columnIndex: number
    borderColor: string
    backgroundColor: string
    isLastSupercolumn: boolean
}): ReactNode {
    const colors = useColors()
    const gridTemplateColumnsDistrict = props.section.districtHeaders.map(() => 'minmax(0, 1fr)').join(' ')

    return (
        <div
            style={{
                gridColumn: props.columnIndex + 2,
                gridRow: props.headerDisplayIndex + 2,
                ...borderStyles({
                    borderColor: props.borderColor,
                    borderBottom: true,
                }),
                backgroundColor: props.backgroundColor,
                display: 'flex',
                ...interSupercolumnBorder(
                    colors,
                    props.isLastSupercolumn,
                ),
            }}
        >
            <div style={{ display: 'grid', gridTemplateColumns: gridTemplateColumnsDistrict, width: '100%', height: '100%' }}>
                {props.section.districtHeaders.map((districtHeaderGroup, bucketIndex) => (
                    <div
                        key={bucketIndex}
                        style={{
                            fontSize: '0.9em',
                            fontWeight: 500,
                            display: 'flex',
                            flexDirection: 'column',
                            justifyContent: 'flex-end',
                            alignItems: 'center',
                            height: '100%',
                            textAlign: 'center',
                            padding,
                            borderRight: bucketIndex === props.section.districtHeaders.length - 1 ? 'none' : `1px solid ${props.borderColor}`,
                        }}
                    >
                        <CongressionalTableSectionDistrictHeader districtLongnames={districtHeaderGroup} />
                    </div>
                ))}
            </div>
        </div>
    )
}

function CongressionalTableSectionDistrictHeader(props: {
    districtLongnames: string[]
}): ReactNode {
    const nav = React.useContext(Navigator.Context)
    const cleanToLong = new Map<string, string[]>()
    props.districtLongnames.forEach((longname) => {
        const clean = cleanDistrictLabel(longname)
        if (!cleanToLong.has(clean)) {
            cleanToLong.set(clean, [])
        }
        cleanToLong.get(clean)!.push(longname)
    })
    return (
        <span style={{ whiteSpace: 'normal' }}>
            {[...cleanToLong.entries()].map(([districtHeader, longnames], headerIndex) => (
                <Fragment key={headerIndex}>
                    {headerIndex > 0 && ' / '}
                    <a
                        {...districtArticleHref(nav, longnames)}
                        style={{ textDecoration: 'none', color: 'inherit' }}
                    >
                        {districtHeader}
                    </a>
                </Fragment>
            ))}
        </span>
    )
}

function CongressionalTableRunRows(props: {
    section: RepresentativesForRegionAndDistrictSet
    run: RepresentativesForRegionAndDistrict
    columnIndex: number
    bucketIndex: number
    isLastBucket: boolean
    borderColor: string
}): ReactNode {
    const colors = useColors()
    assert(props.run.displayRuns.length > 0, `Section ${props.section.contentStartDisplayIndex}-${props.section.contentEndDisplayIndex} has no display runs`)
    const sectionRowCount = props.section.contentEndDisplayIndex - props.section.contentStartDisplayIndex + 1

    return (
        <div
            style={{
                gridColumn: props.bucketIndex + 1,
                gridRow: `1 / ${sectionRowCount + 1}`,
                textAlign: 'center',
                ...borderStyles({
                    borderColor: props.borderColor,
                    borderRight: !props.isLastBucket,
                }),
                display: 'grid',
                gridTemplateRows: 'subgrid',
            }}
        >
            {props.run.displayRuns.map((displayRun, runIndex) => {
                const relativeStartRow = displayRun.startDisplayIndex - props.section.contentStartDisplayIndex + 1
                const relativeEndRow = displayRun.endDisplayIndex - props.section.contentStartDisplayIndex + 1
                const rowStart = Math.min(relativeStartRow, relativeEndRow)
                const spanCount = Math.abs(relativeEndRow - relativeStartRow) + 1
                const bottomRow = rowStart + spanCount - 1
                const isLastDisplayRun = runIndex === props.run.displayRuns.length - 1
                const runFill = displayRunFillStyle(colors, displayRun.representatives)
                return (
                    <div
                        key={displayRun.startDisplayIndex}
                        style={{
                            gridRow: `${rowStart} / span ${spanCount}`,
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            textAlign: 'center',
                            padding,
                            ...(runFill ?? {}),
                            ...borderStyles({
                                borderColor: props.borderColor,
                                borderBottom: !isLastDisplayRun && bottomRow < sectionRowCount,
                            }),
                            gap: '0.1em',
                        }}
                    >
                        {displayRun.representatives.length === 0
                            ? <span style={{ opacity: 0.65, fontWeight: 500 }}>-</span>
                            : displayRun.representatives.map((representative, representativeIndex) => (
                                <span key={representativeIndex} style={{ textAlign: 'center', fontWeight: 500 }}>
                                    <Representative representative={representative} />
                                </span>
                            ))}
                    </div>
                )
            })}
        </div>
    )
}

function CongressionalTableSection(props: {
    section: RepresentativesForRegionAndDistrictSet
    columnIndex: number
    borderColor: string
    sectionBackgroundColor: string
    isLastSectionInSupercolumn: boolean
    isLastSuperColumn: boolean
}): ReactNode {
    const colors = useColors()
    return (
        <Fragment key={`${props.columnIndex}-${props.section.contentStartDisplayIndex}`}>
            {props.section.headerDisplayIndex !== undefined && (
                <CongressionalTableSectionDistrictHeaders
                    section={props.section}
                    headerDisplayIndex={props.section.headerDisplayIndex}
                    columnIndex={props.columnIndex}
                    borderColor={props.borderColor}
                    backgroundColor={props.sectionBackgroundColor}
                    isLastSupercolumn={props.isLastSuperColumn}
                />
            )}

            <div
                style={{
                    gridColumn: props.columnIndex + 2,
                    gridRow: `${props.section.contentStartDisplayIndex + 2} / ${props.section.contentEndDisplayIndex + 3}`,
                    borderBottom: props.isLastSectionInSupercolumn ? undefined : `1px solid ${props.borderColor}`,
                    display: 'grid',
                    gridTemplateColumns: props.section.districtHeaders.map(() => 'minmax(0, 1fr)').join(' '),
                    gridTemplateRows: 'subgrid',
                    ...interSupercolumnBorder(colors, props.isLastSuperColumn),
                }}
            >
                {props.section.congressionalRuns.map((run, bucketIndex) => (
                    <CongressionalTableRunRows
                        key={bucketIndex}
                        section={props.section}
                        run={run}
                        columnIndex={props.columnIndex}
                        bucketIndex={bucketIndex}
                        isLastBucket={bucketIndex === props.section.congressionalRuns.length - 1}
                        borderColor={props.borderColor}
                    />
                ))}
            </div>
        </Fragment>
    )
}

/** Round a calendar year to the nearest multiple of 10 (half-to-even at .5). */
function bankersDecadeForYear(year: number): number {
    const sign = year < 0 ? -1 : 1
    const y = Math.abs(year)
    const q = Math.floor(y / 10)
    const r = y % 10
    if (r < 5) {
        return sign * q * 10
    }
    if (r > 5) {
        return sign * (q + 1) * 10
    }
    const lowerTen = q * 10
    const upperTen = (q + 1) * 10
    return sign * (q % 2 === 0 ? lowerTen : upperTen)
}

function useTableDisplayInfo(regions: CongressionalRegionData[]): {
    scrollContainerRef: React.RefObject<HTMLDivElement>
    preferredScrollableHeight: number
    visibleTerms: number[]
} {
    const scrollContainerRef = React.useRef<HTMLDivElement>(null)
    const [preferredScrollableHeight, setPreferredScrollableHeight] = React.useState<number | undefined>(undefined)
    const [visibleTerms, setVisibleTerms] = React.useState<number[]>([])
    const years = useSelectedYears()
    const minDecade = years.length > 0 ? Math.min(...years) : 2020
    const maxDecade = years.length > 0 ? Math.max(...years) : 2020
    const displayRows = useMemo(() => computeCongressionalWidgetModel(regions).displayRows, [regions])
    const termRows = React.useMemo(
        () => {
            return displayRows.flatMap((row, displayIndex) =>
                row.kind === 'term-label'
                    ? [{ displayIndex, termStart: row.termStart }]
                    : [],
            )
        },
        [displayRows],
    )

    const updateVisibleTerms = React.useCallback(() => {
        const container = scrollContainerRef.current
        if (!container) {
            setVisibleTerms([])
            return
        }
        const containerRect = container.getBoundingClientRect()
        const nextVisibleTerms = termRows.flatMap(({ displayIndex, termStart }) => {
            const rowElement = container.querySelector<HTMLElement>(`[data-display-index="${displayIndex}"]`)
            if (!rowElement) {
                return []
            }
            const rowRect = rowElement.getBoundingClientRect()
            const visibleTop = Math.max(rowRect.top, containerRect.top)
            const visibleBottom = Math.min(rowRect.bottom, containerRect.bottom)
            const visibleHeight = Math.max(0, visibleBottom - visibleTop)
            const rowHeight = rowRect.height
            return rowHeight > 0 && visibleHeight / rowHeight >= 0.5 ? [termStart] : []
        })
        // avoid updating state if no real change
        setVisibleTerms((prevVisibleTerms) => {
            if (JSON.stringify(prevVisibleTerms) === JSON.stringify(nextVisibleTerms)) {
                return prevVisibleTerms
            }
            return nextVisibleTerms
        })
    }, [termRows])

    React.useLayoutEffect(() => {
        const container = scrollContainerRef.current
        if (!container) {
            return
        }

        // Default to the newest terms at the top.
        container.scrollTop = 0

        const targetDisplayIndex = displayRows.reduce((lastIndex, row, displayIndex) => {
            if (
                row.kind === 'term-label'
                && bankersDecadeForYear(row.termStart) >= minDecade
                && bankersDecadeForYear(row.termStart) <= maxDecade
            ) {
                return displayIndex
            }
            return lastIndex
        }, -1)

        if (targetDisplayIndex === -1) {
            setPreferredScrollableHeight(undefined)
            return
        }

        const firstTermDisplayIndex = displayRows.findIndex(row => row.kind === 'term-label')
        const firstTermRow = firstTermDisplayIndex === -1
            ? null
            : container.querySelector<HTMLElement>(`[data-display-index="${firstTermDisplayIndex}"]`)
        const targetRow = container.querySelector<HTMLElement>(`[data-display-index="${targetDisplayIndex}"]`)
        if (!firstTermRow || !targetRow) {
            setPreferredScrollableHeight(undefined)
            return
        }

        // Measure using element rects to avoid offsetParent/positioning artifacts.
        // Tall enough for the header plus term rows from newest through the last term in the selected decade range.
        const containerRect = container.getBoundingClientRect()
        const firstTermRect = firstTermRow.getBoundingClientRect()
        const targetRect = targetRow.getBoundingClientRect()
        const headerHeight = Math.max(0, firstTermRect.top - containerRect.top)
        const termRangeHeight = Math.max(0, targetRect.bottom - firstTermRect.top)
        const horizontalScrollbarHeight = Math.max(0, container.offsetHeight - container.clientHeight)
        const nextHeight = Math.max(220, Math.ceil(headerHeight + termRangeHeight + horizontalScrollbarHeight + 1))
        setPreferredScrollableHeight(previous => (previous === nextHeight ? previous : nextHeight))
        updateVisibleTerms()
    }, [displayRows, minDecade, maxDecade, updateVisibleTerms])

    React.useEffect(() => {
        const container = scrollContainerRef.current
        if (!container) {
            return
        }
        const resizeObserver = new ResizeObserver(() => {
            updateVisibleTerms()
        })
        resizeObserver.observe(container)
        container.addEventListener('scroll', updateVisibleTerms)
        window.addEventListener('resize', updateVisibleTerms)
        updateVisibleTerms()
        return () => {
            resizeObserver.disconnect()
            container.removeEventListener('scroll', updateVisibleTerms)
            window.removeEventListener('resize', updateVisibleTerms)
        }
    }, [updateVisibleTerms])

    return {
        scrollContainerRef,
        preferredScrollableHeight: preferredScrollableHeight ?? 500,
        visibleTerms,
    }
}

function useRestorePreferredScrollableHeightAfterScreenshot(props: {
    isScreenshot: boolean
    scrollContainerRef: React.RefObject<HTMLDivElement | null>
    preferredScrollableHeight: number
}): { scrollableHeight: number } {
    const lastNonScreenshotHeightPxRef = React.useRef<number | undefined>(undefined)
    const wasScreenshotRef = React.useRef<boolean>(props.isScreenshot)
    const [scrollableHeight, setScrollableHeight] = React.useState<number | undefined>(undefined)

    React.useLayoutEffect(() => {
        if (props.isScreenshot) {
            const container = props.scrollContainerRef.current
            if (container) {
                lastNonScreenshotHeightPxRef.current = Math.ceil(container.getBoundingClientRect().height)
            }
        }
        else if (wasScreenshotRef.current) {
            setScrollableHeight(lastNonScreenshotHeightPxRef.current)
        }
        wasScreenshotRef.current = props.isScreenshot
    }, [props.isScreenshot, props.scrollContainerRef])

    React.useLayoutEffect(() => {
        if (props.isScreenshot) {
            return
        }
        const container = props.scrollContainerRef.current
        if (!container) {
            return
        }
        const updateHeight = (): void => {
            lastNonScreenshotHeightPxRef.current = Math.ceil(container.getBoundingClientRect().height)
        }
        updateHeight()
        const resizeObserver = new ResizeObserver(updateHeight)
        resizeObserver.observe(container)
        container.addEventListener('scroll', updateHeight)
        window.addEventListener('resize', updateHeight)
        return () => {
            resizeObserver.disconnect()
            container.removeEventListener('scroll', updateHeight)
            window.removeEventListener('resize', updateHeight)
        }
    }, [props.isScreenshot, props.preferredScrollableHeight, props.scrollContainerRef])

    return { scrollableHeight: scrollableHeight ?? props.preferredScrollableHeight }
}

function normalizeWidths(
    totalWidth: number,
    unnormalizedTermColumnPercent: number,
    unnormalizedDataColumnPercents: number[],
    normalizeTo: 'include-header' | 'just-data-columns',
): { normalizedTermColumnPercent: number, normalizedDataColumnPercents: number[] } {
    switch (normalizeTo) {
        case 'include-header': {
            const newDenom = unnormalizedTermColumnPercent + unnormalizedDataColumnPercents.reduce((a, b) => a + b, 0)
            const reweightFactor = totalWidth / newDenom
            return {
                normalizedTermColumnPercent: unnormalizedTermColumnPercent * reweightFactor,
                normalizedDataColumnPercents: unnormalizedDataColumnPercents.map(percent => percent * reweightFactor),
            }
        }
        case 'just-data-columns': {
            const newDenom = unnormalizedDataColumnPercents.reduce((a, b) => a + b, 0)
            const reweightFactor = (totalWidth - unnormalizedTermColumnPercent) / newDenom
            return {
                normalizedTermColumnPercent: unnormalizedTermColumnPercent,
                normalizedDataColumnPercents: unnormalizedDataColumnPercents.map(percent => percent * reweightFactor),
            }
        }
    }
}

function CongressionalRepresentativesTableActual(props: {
    model: CongressionalTableModel
    totalWidthPercent: number
    unnormalizedTermColumnPercent: number
    unnormalizedDataColumnPercents: number[]
    normalizeTo: 'include-header' | 'just-data-columns'
}): ReactNode {
    const colors = useColors()
    const borderColor = colors.textMain
    const panelBackground = colors.slightlyDifferentBackground
    const {
        normalizedTermColumnPercent,
        normalizedDataColumnPercents,
    } = normalizeWidths(
        props.totalWidthPercent,
        props.unnormalizedTermColumnPercent,
        props.unnormalizedDataColumnPercents,
        props.normalizeTo,
    )
    const gridTemplateColumns = `${normalizedTermColumnPercent}% ${normalizedDataColumnPercents.map(width => `${width}%`).join(' ')}`

    return (
        <div
            id="congressional-representatives-table-actual"
            style={{
                display: 'grid',
                gridTemplateColumns,
                gridTemplateRows: `auto repeat(${props.model.displayRows.length}, minmax(0, auto))`,
                alignItems: 'stretch',
            }}
        >
            <div
                style={{
                    gridColumn: 1,
                    gridRow: 1,
                    padding,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'flex-end',
                    textAlign: 'right',
                    borderRight: `1px solid ${borderColor}`,
                    borderBottom: `1px solid ${borderColor}`,
                    backgroundColor: panelBackground,
                    fontWeight: 500,
                }}
            >
                Term
            </div>
            <CongressionalTableColumnHeaders
                supercolumns={props.model.supercolumns}
                borderColor={borderColor}
                panelBackground={panelBackground}
            />

            <CongressionalTableTermLabels
                displayRows={props.model.displayRows}
                borderColor={borderColor}
            />

            {props.model.supercolumns.map((supercolumn, columnIndex) => supercolumn.sections.map((section, sectionIndex) => {
                return (
                    <CongressionalTableSection
                        key={`${columnIndex}-${section.contentStartDisplayIndex}`}
                        section={section}
                        columnIndex={columnIndex}
                        borderColor={borderColor}
                        sectionBackgroundColor={colors.background}
                        isLastSectionInSupercolumn={sectionIndex === supercolumn.sections.length - 1}
                        isLastSuperColumn={columnIndex === props.model.supercolumns.length - 1}
                    />
                )
            }))}
        </div>
    )
}

const maxColumnsBeforeScroll = 7

function numEffectiveColumns(model: CongressionalTableModel): number {
    const supercolumnCount = model.supercolumns.length
    const maxColumnsPerSupercolumn = Math.max(
        1,
        ...model.supercolumns.flatMap(supercolumn =>
            supercolumn.sections.map(section => section.districtHeaders.length),
        ),
    )
    return supercolumnCount * maxColumnsPerSupercolumn
}

function CongressionalRepresentativesWithScroll(props: {
    regions: CongressionalRegionData[]
    widthLeftHeader: number
    columnWidth: number
    extraSpaceRight: number[]
}): ReactNode {
    const isScreenshot = useScreenshotMode()
    const { scrollContainerRef, preferredScrollableHeight, visibleTerms } = useTableDisplayInfo(props.regions)
    const { scrollableHeight } = useRestorePreferredScrollableHeightAfterScreenshot({
        isScreenshot,
        scrollContainerRef,
        preferredScrollableHeight,
    })

    const model = useMemo(
        () => {
            let regionsToUse = props.regions
            if (isScreenshot) {
                // filter for the ones previously visible
                regionsToUse = props.regions.map(region => ({
                    ...region,
                    representatives: region.representatives.flatMap(representative => subsetEntryToTerms(representative, visibleTerms)),
                }))
            }
            return computeCongressionalWidgetModel(regionsToUse)
        },
        [props.regions, visibleTerms, isScreenshot],
    )
    const effectiveColumnCount = numEffectiveColumns(model)
    const needsHorizontalScroll = effectiveColumnCount > maxColumnsBeforeScroll
    const expansionFactor = needsHorizontalScroll ? effectiveColumnCount / maxColumnsBeforeScroll : 1
    const columnSizes = model.supercolumns.map((_, columnIndex) => props.columnWidth + props.extraSpaceRight[columnIndex])
    if (isScreenshot) {
        // put the entire table in, but shrunk down to fit, by changing the font sizes
        return (
            <div
                style={{
                    fontSize: `${100 / expansionFactor}%`,
                }}
            >
                <CongressionalRepresentativesTableActual
                    model={model}
                    totalWidthPercent={100}
                    unnormalizedTermColumnPercent={props.widthLeftHeader}
                    unnormalizedDataColumnPercents={columnSizes}
                    normalizeTo="just-data-columns"
                />
            </div>
        )
    }
    const totalExpandedPercent = props.widthLeftHeader + expansionFactor * (100 - props.widthLeftHeader)
    const normalizedTermColumnPercent = props.widthLeftHeader / totalExpandedPercent * 100
    const normalizedDataColumnPercents = model.supercolumns.map((_, i) => {
        const basePercent = props.columnWidth + props.extraSpaceRight[i]
        return expansionFactor * basePercent / totalExpandedPercent * 100
    })
    const expandedWidth = `${totalExpandedPercent}%`

    return (
        <div
            id="congressional-representatives-scroll-view"
            ref={scrollContainerRef}
            style={{
                width: '100%',
                marginTop: '4px',
                marginBottom: '4px',
                resize: 'vertical',
                overflowX: needsHorizontalScroll ? 'auto' : 'visible',
                overflowY: 'auto',
                height: `${scrollableHeight}px`,
                minHeight: '220px',
                boxSizing: 'border-box',
            }}
        >
            <div
                style={{
                    width: needsHorizontalScroll ? expandedWidth : '100%',
                }}
            >
                <CongressionalRepresentativesTableActual
                    model={model}
                    // leave a tiny bit of wiggle room for the scroll bar.
                    totalWidthPercent={99}
                    unnormalizedTermColumnPercent={normalizedTermColumnPercent}
                    unnormalizedDataColumnPercents={normalizedDataColumnPercents}
                    normalizeTo="include-header"
                />
            </div>
        </div>
    )
}

export function CongressionalRepresentativesWidget(props: {
    regions: CongressionalRegionData[]
    widthLeftHeader: number
    columnWidth: number
    extraSpaceRight: number[]
}): ReactNode {
    assert(props.regions.length > 0, 'CongressionalRepresentativesWidget requires at least one region')
    return (
        <CongressionalRepresentativesWithScroll
            regions={props.regions}
            widthLeftHeader={props.widthLeftHeader}
            columnWidth={props.columnWidth}
            extraSpaceRight={props.extraSpaceRight}
        />
    )
}

function formatTermLabel(termStart: number): string {
    return `${termStart}-${String(termStart + 2).slice(2)}`
}
